INSERT INTO `product` (`product_id`, `product_name`, `product_description`, `product_image`, `product_price`, `product_details`, `category_id`) VALUES
(1, 'Burger', 'Crafted to perfection, our Miniature Burgers will add a touch of realism to your dollhouse. Made with precise attention to detail, these perfectly scaled burgers are an essential addition to any miniature kitchen. Indulge in 1:12 scale perfection with our Dollhouse Miniature Burgers. Types available: Type A, Type B.', '/smallmart/website/assets/products/burger_1.jpg', 32, 'variants=\"Type\":{\"Type A\":\"/smallmart/website/assets/products/burger_1.jpg\",\"Type B\":\"/smallmart/website/assets/products/burger_2.jpg\"}', '1'),
(2, 'Brownie', 'Enhance your dollhouse with this intricately detailed brownie miniature. Each piece is handcrafted to perfection, adding a touch of realism to your miniature world. Made with high-quality materials for long-lasting durability. Perfect for collectors or dollhouse enthusiasts.', '/smallmart/website/assets/products/brownie_1.jpg', 40, 'featured=2', '9'),
(3, 'Bread', 'Experience the charm of a dollhouse with our miniatures. Each random piece of bread adds a unique touch to your collection. Expertly crafted with attention to detail, these miniatures are essential for any dollhouse enthusiast. Bring your imagination to life with these intricate pieces.', '/smallmart/website/assets/products/bread_1.jpg', 24, 'featured=9', '8'),
(4, 'Alcoholic Beverage Bottle', 'This miniature alcoholic beverage bottle (random colour) is the perfect addition to any dollhouse or collection. Made with attention to detail, this tiny bottle adds a realistic touch to any miniature setting. Crafted with high-quality materials, it is sure to impress and enhance any display.', '/smallmart/website/assets/products/alcoholic-beverage-bottle_1.jpg,/smallmart/website/assets/products/alcoholic-beverage-bottle_2.jpg', 32, 'featured=10', '8'),
(5, 'Air Fryer', 'This Miniature Air Fryer is the perfect addition to your doll house kitchen! With its realistic details and tiny size, it brings authenticity to your miniature world. Add this to your collection and bring your doll house kitchen to life.', '/smallmart/website/assets/products/air-fryer_1.jpg,/smallmart/website/assets/products/air-fryer_2.jpg,/smallmart/website/assets/products/air-fryer_3.jpg', 514, 'featured=8', '8,9'),
(6, 'Cooking Decor Set', 'Enhance your child\'s imaginative play with our Cooking Decor Set, complete with a doll house for added fun. Stimulate creativity and fine motor skills as they pretend to cook and decorate with realistic accessories. Perfect for ages 3 and up.', '/smallmart/website/assets/products/cooking-decor-set_1.jpg,/smallmart/website/assets/products/cooking-decor-set_2.jpg,/smallmart/website/assets/products/cooking-decor-set_3.jpg,/smallmart/website/assets/products/cooking-decor-set_4.jpg,/smallmart/website/assets/products/cooking-decor-set_5.jpg,/smallmart/website/assets/products/cooking-decor-set_6.jpg', 138, '', '1'),
(7, 'Coffee Mug', 'This miniature coffee mug is the perfect addition to any dollhouse. Expertly crafted, it provides a realistic touch to any miniature kitchen or dining room. Made with precision and attention to detail, it is a must-have for any dollhouse enthusiast.', '/smallmart/website/assets/products/coffee-mug_1.jpg', 24, 'featured=4', '9'),
(8, 'Clock', 'Miniature Clock (random colour). Expertly crafted, this clock is a perfect addition to any dollhouse. With its miniature size, it adds a touch of elegance and functionality to any room.', '/smallmart/website/assets/products/clock_1.jpg', 17, 'featured=3', '9'),
(9, 'Carpet', 'Miniature Carpet (15 cm x 10 cm). Expertly crafted for dollhouse enthusiasts, this miniature carpet adds a touch of elegance and realism to any miniature setting. Made to scale, its intricate design and quality materials make it a must-have for any collector. Available colours: Light Blue, Red.', '/smallmart/website/assets/products/carpet_2.jpg', 142, 'featured=1,variants=\"Color\":{\"Light blue\":\"/smallmart/website/assets/products/carpet_1.jpg\",\"Red\":\"/smallmart/website/assets/products/carpet_2.jpg\"}', '9'),
(10, 'Candle Set', 'Crafted for dollhouse enthusiasts, this Miniature Candle Set adds a realistic touch to any miniature scene. Hand-crafted with intricate detail, these candles provide the perfect accent piece for creating a cozy and charming atmosphere. A must-have set for your miniature collection.', '/smallmart/website/assets/products/candle-set_1.jpg', 119, 'featured=1', '8'),
(11, 'Biscuits', 'With a realistic design and intricate details, our Miniature Biscuits is a delightful addition to any dollhouse. Crafted with precision, this tiny treat adds a touch of charm to your miniature world. Immerse yourself in the tiny world with our lifelike miniature biscuits.', '/smallmart/website/assets/products/biscuits_2.jpg', 16, 'featured=11,variants=\"Biscuit\":{\"Parle-G\":\"/smallmart/website/assets/products/biscuits_5.jpg\",\"Bourbon\":\"/smallmart/website/assets/products/biscuits_2.jpg\",\"Good Day\":\"/smallmart/website/assets/products/biscuits_1.jpg\",\"Lotus Biscoff\":\"/smallmart/website/assets/products/biscuits_3.jpg\",\"Marie-Gold\":\"/smallmart/website/assets/products/biscuits_4.jpg\",\"Oreo\":\"/smallmart/website/assets/products/biscuits_6.jpg\",\"JimJam\":\"/smallmart/website/assets/products/biscuits_7.jpg\",\"Salt Biscuit\":\"/smallmart/website/assets/products/biscuits_8.jpg\",\"Butter Biscuit\":\"/smallmart/website/assets/products/biscuits_9.jpg\"}', '8'),
(12, 'Chair', 'This dollhouse miniature chair per piece random colour is expertly crafted for a realistic and charming addition to your miniature setting. Made with precision and detail, it boasts an authentic design that will elevate the aesthetic of any miniature scene. Enhance the ambiance and visual appeal with this delightful chair.', '/smallmart/website/assets/products/chair_2.jpg', 59, 'featured=7,discounted-price=43,variants=\"Colour\":{\"Purple\":\"/smallmart/website/assets/products/chair_7.jpg\",\"White\":\"/smallmart/website/assets/products/chair_1.jpg\",\"Green\":\"/smallmart/website/assets/products/chair_6.jpg\",\"Red\":\"/smallmart/website/assets/products/chair_5.jpg\",\"Pink\":\"/smallmart/website/assets/products/chair_3.jpg\",\"Light blue\":\"/smallmart/website/assets/products/chair_4.jpg\"}', '10'),
(13, 'Cookies Set', 'Expertly crafted and detailed, this Cookies Set features dollhouse miniatures that will enhance any playtime experience. Each piece is made with high-quality materials and intricate designs, providing endless opportunities for imaginative play. With a variety of delectable treats, this set is perfect for tea parties, kitchen play, and more.', '/smallmart/website/assets/products/cookies-set_1.jpg', 103, 'featured=5,discounted-price=82', '10'),
(14, 'Design Plate', 'This dollhouse miniature  design plate per piece random is perfect for giving your dollhouse a realistic touch. Each plate is unique and adds character to your miniature home. Expertly crafted to resemble real plates, these pieces are a must-have for dollhouse enthusiasts and collectors.', '/smallmart/website/assets/products/design-plate_1.jpg,/smallmart/website/assets/products/design-plate_2.jpg', 32, '', ''),
(15, 'Donut Flower Vase', 'Introducing the Donut Flower Vase, a dollhouse miniature that adds a touch of whimsy to any home decor. Crafted with the finest details, this vase is a perfect addition to your miniature collection. With its unique design and intricate craftsmanship, it will surely be the centerpiece of any room.', '/smallmart/website/assets/products/donut-flower-vase_1.jpg', 63, 'featured=3,discounted-price=52,variants=\"Colour\":{\"Green\":\"/smallmart/website/assets/products/donut-flower-vase_1.jpg,/smallmart/website/assets/products/donut-flower-vase_7.jpg\",\"Flourescent\":\"/smallmart/website/assets/products/donut-flower-vase_4.jpg,/smallmart/website/assets/products/donut-flower-vase_5.jpg\",\"Orange\":\"/smallmart/website/assets/products/donut-flower-vase_3.jpg,/smallmart/website/assets/products/donut-flower-vase_6.jpg\",\"Pink\":\"/smallmart/website/assets/products/donut-flower-vase_2.jpg\"}', '10'),
(16, 'Dustbin', 'Expertly crafted, this 1 piece dollhouse miniature dustbin is the perfect addition to any dollhouse. Made with attention to detail and precision, it adds a realistic touch to any miniature setting. Made to scale and durable, it provides a functional and aesthetically pleasing solution for your dollhouse\'s waste management needs.', '/smallmart/website/assets/products/dustbin_1.png', 41, 'featured=2,discounted-price=29', '10'),
(17, 'Ferrero Rocher Chocolate', 'This miniature Ferrero rocher is the perfect addition to any dollhouse, adding a touch of realism and charm. Crafted with intricate details, it will bring your miniature world to life. Made with high-quality materials, it is a must-have for any collector or enthusiast. Elevate your miniature scenes with this exquisite piece.', '/smallmart/website/assets/products/ferrero-rocher-chocolate_1.jpg,/smallmart/website/assets/products/ferrero-rocher-chocolate_2.jpg', 138, 'featured=14', '8'),
(18, 'Fish Tank', 'This Miniature Fish Tank per piece is the perfect addition to any dollhouse setup. Made with precision and attention to detail, it adds a touch of realism to your miniature world. Crafted with high-quality materials, it is both durable and visually appealing. Bring your dollhouse to life with this exquisite dollhouse miniature.', '/smallmart/website/assets/products/fish-tank_1.jpg', 296, 'featured=3', '8'),
(19, 'Flower Potted Vase', 'Expertly crafted miniature flower potted vase per piece, perfect for dollhouses or adding a touch of elegance to any small scale setting. Fine attention to detail and high-quality materials make this piece a must-have for collectors and hobbyists alike.', '/smallmart/website/assets/products/flower-potted-vase_1.jpg', 36, 'featured=1,discounted-price=30,variants=\"Flower vase\":{\"Type A\":\"/smallmart/website/assets/products/flower-potted-vase_1.jpg\",\"Type B\":\"/smallmart/website/assets/products/flower-potted-vase_2.jpg\",\"Type C\":\"/smallmart/website/assets/products/flower-potted-vase_3.jpg\",\"Type D\":\"/smallmart/website/assets/products/flower-potted-vase_4.jpg\",\"Type E\":\"/smallmart/website/assets/products/flower-potted-vase_5.jpg\",\"Type F\":\"/smallmart/website/assets/products/flower-potted-vase_6.jpg\"}', '10'),
(20, 'French Fries', 'Expertly crafted to be a perfect scale replica, these Miniature French Fries will add realistic charm to your dollhouse. Created with precision and attention to detail, this tiny beauty is a true collector\'s item.', '/smallmart/website/assets/products/french-fries_1.jpg', 24, 'featured=4,discounted-price=12', '10'),
(21, 'Guitar', 'Our Guitar is a beautifully crafted miniature, perfect for adding a touch of musical charm to any dollhouse. Made with expert precision and attention to detail, it provides an accurate representation of the real-life instrument. Complete your dollhouse with this high-quality guitar and enhance its overall aesthetic.', '/smallmart/website/assets/products/guitar_1.jpg', 36, 'featured=6,discounted-price=28', '10'),
(22, 'Gulab Jamun Set', 'Experience the deliciousness of Gulab Jamun in a miniature form with our Miniature Gulab Jamun Set. This set includes dollhouse miniatures that are made with precision and attention to detail. Bring a taste of India to your dollhouse and add a touch of authenticity to your collection.', '/smallmart/website/assets/products/gulab-jamun-set_1.jpg', 103, '', ''),
(23, 'Hanging Swing', 'This dollhouse miniature hanging swing adds a charming touch to any dollhouse or miniature scene. With expertly crafted details, this miniature swing captures the essence of a real-life swing, providing a realistic addition to your mini world. Perfect for collectors and enthusiasts alike.', '/smallmart/website/assets/products/hanging-swing_1.jpg,/smallmart/website/assets/products/hanging-swing_2.jpg', 387, 'featured=2', '8'),
(24, 'Laddu Sweet', 'This 3 piece of Laddu Sweet features a dollhouse miniature design, providing a charming and realistic touch to any miniature setting. Handcrafted with intricate detail, it adds a delightful and authentic touch to your miniature collection. Made with high-quality materials, it is a perfect addition for miniature enthusiasts.', '/smallmart/website/assets/products/laddu-sweet_1.jpg', 47, 'featured=9,discounted-price=38', '10'),
(25, 'Laddu Sweet Box', 'This Laddu Sweet Box ( Box design may vary)is a miniature replica of the traditional sweet box often found in Indian households. With its intricate details and realistic design, it is perfect for dollhouse enthusiasts or as a unique piece for home decor. Handcrafted with precision, this miniature Laddu Sweet Box is a delightful addition to any collection.', '/smallmart/website/assets/products/laddu-sweet-box_1.jpg,/smallmart/website/assets/products/laddu-sweet-box_2.jpg,/smallmart/website/assets/products/laddu-sweet-box_3.jpg', 174, '', ''),
(26, 'Macroon Box', 'This Miniature Macroon Box is a 1-inch dollhouse miniature, perfect for adding a touch of charm and realism to your miniature scenes. Crafted with attention to detail, this miniature is sure to delight any miniature enthusiast. Add it to your collection and create beautiful, realistic scenes.', '/smallmart/website/assets/products/macroon-box_1.jpg,/smallmart/website/assets/products/macroon-box_2.jpg', 150, 'featured=10', '9'),
(27, 'Milk Cream Sweet Box', 'This Milk Cream Sweet Box ( Box design may vary) is a dollhouse miniature that will add the perfect touch of sweetness to any dollhouse interior. Made with high-quality materials and attention to detail, this miniature will bring a realistic and charming element to your decor. Perfect for collectors and dollhouse enthusiasts.', '/smallmart/website/assets/products/milk-cream-sweet-box_1.jpg,/smallmart/website/assets/products/milk-cream-sweet-box_2.jpg', 174, '', ''),
(28, 'Mini Flower Bud Vase', 'Mini Flower Bud  Vase per piece .This dollhouse miniature is delicately crafted to add a touch of charm to your miniature world. With its intricate details and realistic design, it\'s the perfect choice for any dollhouse enthusiast. Bring your miniature world to life with the Mini Flower Bud.', '/smallmart/website/assets/products/mini-flower-bud-vase_1.jpg', 40, 'featured=13', '8'),
(29, 'Muffins', 'Enhance your dollhouse miniature set with these delicate Miniature Muffins. Made with attention to detail, these tiny treats add a realistic touch to any miniature kitchen. Perfect for collectors or dollhouse enthusiasts looking to elevate their display.', '/smallmart/website/assets/products/muffins_1.jpg', 24, '', ''),
(30, 'Pastry Set', 'This Pastry Set includes a beautifully crafted dollhouse miniature, perfect for collectors and enthusiasts alike. Each intricate detail is meticulously designed, providing a realistic and charming addition to any collection. Made with high-quality materials, this set is sure to impress with its stunning craftsmanship.', '/smallmart/website/assets/products/pastry-set_1.jpg,/smallmart/website/assets/products/pastry-set_2.jpg,/smallmart/website/assets/products/pastry-set_3.jpg,/smallmart/website/assets/products/pastry-set_4.jpg,/smallmart/website/assets/products/pastry-set_5.jpg', 119, '', ''),
(31, 'Pizza With Box', 'Expertly crafted with realistic details, this miniature pizza is the perfect addition to any dollhouse. Made to scale, it comes complete with a tiny pizza box for an added touch of authenticity. Add this charming piece to your collection today.', '/smallmart/website/assets/products/pizza-with-box_1.jpg,/smallmart/website/assets/products/pizza-with-box_2.jpg,/smallmart/website/assets/products/pizza-with-box_3.jpg', 119, '', '8'),
(32, 'Radio', 'Expertly crafted and perfectly detailed, this dollhouse miniature Radio adds an authentic touch to any miniature setting. Made with precision and attention to detail, this model accurately captures the design and functionality of a real radio. Display it in your dollhouse or collection for a touch of nostalgia.', '/smallmart/website/assets/products/radio_1.jpg,/smallmart/website/assets/products/radio_2.jpg', 55, 'featured=10,discounted-price=42', '10'),
(33, 'Roll Pastry', 'Experience the realistic detail of our 1 Piece Roll Pastry miniature. Crafted with expert precision, each piece captures the intricate layers of a traditional bun, adding stunning realism to your dollhouse scenes. Made with high-quality materials, your collection will stand out with our miniature buns.', '/smallmart/website/assets/products/roll-pastry_1.jpg', 24, '', ''),
(34, 'Sewing Machine', 'This sewing machine is the perfect addition to any dollhouse, featuring a miniature design for realistic play. With its intricate details and realistic features, it provides endless creative opportunities for children to develop their sewing skills while having fun. A must-have for any dollhouse enthusiast.', '/smallmart/website/assets/products/sewing-machine_1.jpg', 46, 'featured=8,discounted-price=39', '10'),
(35, 'Suitcase', 'This miniature dollhouse suitcase is the perfect addition for any collector or enthusiast. Crafted with intricate details, this piece is made from high-quality materials for durability and authenticity. Display it in your dollhouse or use it for imaginative play, the possibilities are endless. Enhance your miniature world with this charming suitcase.', '/smallmart/website/assets/products/suitcase_1.jpg,/smallmart/website/assets/products/suitcase_2.jpg', 36, 'featured=7', '9'),
(36, 'Sweet Pidi Kozhukattai', '3 piece Experience the enchanting world of miniature dollhouses with Sweet Pidi kozhukattai .  Each piece is expertly crafted for a realistic and intricate design, perfect for collectors and hobbyists alike. Bring your imagination to life and create stunning scenes with these detailed miniature pieces.', '/smallmart/website/assets/products/sweet-pidi-kozhukattai_1.jpg', 47, '', ''),
(37, 'Swing', 'Expertly crafted for dollhouse enthusiasts, this Swing is a 1/12 scale miniature that adds a touch of charm to any dollhouse setting. Enjoy the intricate details and impeccable design of this realistic addition to your collection.', '/smallmart/website/assets/products/swing_1.jpg,/smallmart/website/assets/products/swing_2.jpg,/smallmart/website/assets/products/swing_3.jpg', 435, 'featured=12', '8'),
(38, 'Telephone', 'This telephone is a realistic dollhouse miniature that will add authenticity to your miniature world. With intricate details and high-quality construction, it is the perfect addition to any miniature scene. Bring your imagination to life with this miniature telephone.', '/smallmart/website/assets/products/telephone_1.jpg', 36, 'featured=9', '9'),
(39, 'Traditional Lamp', 'This traditional lamp is a dollhouse miniature that adds a touch of elegance to any room. Crafted with intricate details, this lamp will enhance the beauty of your miniature home. Made with quality materials, it is a perfect addition to any collector\'s collection.', '/smallmart/website/assets/products/traditional-lamp_1.jpg,/smallmart/website/assets/products/traditional-lamp_2.jpg,/smallmart/website/assets/products/traditional-lamp_3.jpg', 174, '', ''),
(40, 'Traditional Radio', 'This dollhouse miniature traditional radio is a perfect addition to any miniature home. It boasts realistic details and intricate design, making it a charming and authentic piece for your collection. With its small size, it will fit perfectly into any tiny room, allowing your miniature family to enjoy music and news just like in a real home.', '/smallmart/website/assets/products/traditional-radio_1.jpg,/smallmart/website/assets/products/traditional-radio_2.jpg', 36, '', ''),
(41, 'Traditional Set', 'Experience the timeless charm and intricate detail of our Traditional Set. This set features a beautifully crafted dollhouse miniature that will transport you to a world of imagination and creativity. Adorned with intricate designs and classic features, this set is perfect for collectors and dollhouse enthusiasts alike.', '/smallmart/website/assets/products/traditional-set_1.jpg', 95, 'variants=\"Traditional Set\":{\"Type A\":\"/smallmart/website/assets/products/traditional-set_7.jpg\",\"Type B\":\"/smallmart/website/assets/products/traditional-set_1.jpg,/smallmart/website/assets/products/traditional-set_4.jpg\",\"Type C\":\"/smallmart/website/assets/products/traditional-set_3.jpg,/smallmart/website/assets/products/traditional-set_5.jpg\",\"Type D\":\"/smallmart/website/assets/products/traditional-set_2.jpg,/smallmart/website/assets/products/traditional-set_6.jpg\"}', ''),
(42, 'Trophy', 'This miniature dollhouse is a must-have for any collector. Crafted with exquisite detail, this 1/12 scale replica boasts hand-painted features and intricate furnishings. Perfect for showcasing your love for exquisite craftsmanship and interior design.', '/smallmart/website/assets/products/trophy_1.jpg,/smallmart/website/assets/products/trophy_2.jpg,/smallmart/website/assets/products/trophy_3.jpg,/smallmart/website/assets/products/trophy_4.jpg', 111, 'featured=5', '9'),
(43, 'Vase Set', 'Expertly crafted with precision, this miniature set of vases is the perfect addition to any dollhouse. Made with attention to detail and high-quality materials, these vases provide a realistic and elegant touch to any miniature home. Enhance your dollhouse decor with this beautiful vase set.', '/smallmart/website/assets/products/vase-set_1.jpg', 59, 'variants=\"Colour\":{\"Purple\":\"/smallmart/website/assets/products/vase-set_1.jpg,/smallmart/website/assets/products/vase-set_6.jpg,/smallmart/website/assets/products/vase-set_7.jpg\",\"Pink\":\"/smallmart/website/assets/products/vase-set_2.jpg,/smallmart/website/assets/products/vase-set_5.jpg\",\"Light blue\":\"/smallmart/website/assets/products/vase-set_3.jpg,/smallmart/website/assets/products/vase-set_4.jpg\"}', ''),
(44, 'Waffle Toaster', 'Introducing our Waffle Toaster, perfect for any miniature collection. With its compact design, it\'s easy to store and display. Enjoy perfectly toasted waffles without taking up too much space. A must-have for avid collectors.', '/smallmart/website/assets/products/waffle-toaster_1.jpg,/smallmart/website/assets/products/waffle-toaster_2.jpg,/smallmart/website/assets/products/waffle-toaster_3.jpg,/smallmart/website/assets/products/waffle-toaster_4.jpg', 190, 'featured=6', '9'),
(45, 'Water Filter', 'This Water Filter is a perfect addition to any dollhouse. With its miniature size, it will fit seamlessly into any room. Add a touch of realism to your dollhouse.', '/smallmart/website/assets/products/water-filter_1.jpg', 36, '', ''),
(46, 'Mini LED Fireplace Set', 'The Mini LED Fireplace Set is a carefully designed dollhouse accessory that simulates a realistic fire effect. Ideal for enhancing the aesthetic of miniature environments, this fireplace adds a touch of warmth and authenticity, making it an engaging focal point in any dollhouse setting.', '/smallmart/website/assets/products/mini-led-fireplace-set_1.jpg,/smallmart/website/assets/products/mini-led-fireplace-set_2.jpg,/smallmart/website/assets/products/mini-led-fireplace-set_3.jpg,/smallmart/website/assets/products/mini-led-fireplace-set_4.jpg,/smallmart/website/assets/products/mini-led-fireplace-set_5.jpg,/smallmart/website/assets/products/mini-led-fireplace-set_6.jpg,/smallmart/website/assets/products/mini-led-fireplace-set_7.jpg', 1262, '', '1'),
(47, 'Breakfast Dining Table Set', 'The Breakfast Dining Table Set is a meticulously crafted dollhouse miniature designed with attention to detail. It serves as an ideal addition for enhancing the realism of miniature environments. Measuring accurately to scale, this set allows for intricate storytelling and decoration in dollhouse displays.', '/smallmart/website/assets/products/breakfast-dining-table-set_1.jpg,/smallmart/website/assets/products/breakfast-dining-table-set_2.jpg,/smallmart/website/assets/products/breakfast-dining-table-set_3.jpg', 1343, '', '1');
INSERT INTO `review` (`review_id`, `review_title`, `review_text`, `review_published_datetime`, `review_rating`, `product_id`, `user_id`) VALUES
(1, 'Mini Breakfast Win', 'This miniature waffle toaster looks adorable and surprisingly realistic. The detailing on the metal finish and tiny waffle grooves is impressive, and it adds the perfect touch to any dollhouse kitchen or craft scene. Only downside: the “waffles” don’t fully slide in, but for display purposes it’s fantastic.', '2026-01-14 09:42:18', 4.5, 44, 1),
(2, 'Mighty Mini Guitar', 'This tiny guitar prop is beautifully crafted with painted strings and a glossy body finish that gives it a premium feel. It fits perfectly in miniature music sets and photoshoots. The proportions are spot-on, making it look almost real at a glance.', '2026-02-11 18:11:54', 5, 21, 2),
(3, 'Solid Mini Seat', 'A clean, classic miniature chair with great balance and craftsmanship. The legs are sturdy and it sits perfectly on flat surfaces without wobbling. Could use a bit more texture or detail, but overall it’s a great addition to any prop collection.', '2025-12-23 14:27:03', 4, 12, 3),
(4, 'Tiny Fries, Big Win', 'These miniature French fries are unbelievably cute and super realistic! The coloring replicates the perfect golden fry, and the tiny carton packaging enhances the charm. They photograph extremely well and add personality to any food‑themed prop scene.', '2026-01-08 20:05:41', 5, 20, 4),
(5, 'Mini Swing Magic', 'This miniature swing has a whimsical look and great motion for posing. The ropes and seat are well-made, and it adds a magical touch to outdoor or fantasy setups. Slightly delicate, so handle gently, but visually it’s amazing.', '2026-02-01 11:36:22', 4.5, 37, 5),
(6, 'Tiny Fryer Fail', 'This miniature air fryer is honestly more frustrating than fun. The plastic feels cheap, the door doesn’t close properly, and the paint job looks rushed with uneven edges. It’s supposed to resemble a modern air fryer, but the proportions are noticeably off, making it look awkward in any prop setup. Even as a display piece, it falls short and sticks out in the worst way. I really expected better quality for something this small and simple.', '2025-11-28 16:54:09', 1.5, 5, 6),
(7, 'Not Worth It', 'Not satisfied with the build or durability.', '2026-01-29 10:41:57', 1, 10, 7),
(8, 'Love This!', 'Would absolutely buy again!', '2025-10-12 19:08:23', 4.5, 10, 8),
(9, 'Decent Quality', 'Meets expectations but not outstanding.', '2025-03-26 14:56:09', 2.5, 10, 9),
(10, 'Love This!', 'Exactly what I hoped for, very pleased!', '2025-12-28 17:34:12', 4.5, 19, 10),
(11, 'Does the Job', 'Not perfect but acceptable.', '2025-06-29 11:19:46', 3, 19, 11),
(12, 'Could Be Better', 'Would not recommend based on my experience.', '2025-03-28 15:52:08', 1, 19, 12),
(13, 'Good idea, mixed execution', 'Conceptually, the burger is a great idea, though execution could be more refined in certain areas. Overall, I am happy with how this burger looks in a miniature display.', '2026-08-20 06:52:46', 4.4, 1, 1),
(14, 'Not quite what I hoped for', 'I had higher expectations for this burger, and while it is usable, it did not fully meet what I was hoping for. It is acceptable overall, though improvement would make this burger more appealing.', '2026-02-27 23:41:30', 3, 1, 2),
